// Extract YouTube URL from Discord message
const message = $input.first().json;
const messageContent = message.content;

if (!messageContent) {
  return [];
}

// Match youtube.com/watch?v= and youtu.be/ formats
const ytRegex = /(?:https?:\/\/)?(?:www\.)?(?:youtube\.com\/(?:watch\?v=|live\/|shorts\/)|youtu\.be\/)([a-zA-Z0-9_-]{11})(?:[&?][^\s]*)*/;
const match = messageContent.match(ytRegex);

if (!match) {
  return [{
    json: {
      is_youtube: false,
      channel_id: message.channelId
    }
  }];
}

const videoId = match[1];
const videoUrl = `https://www.youtube.com/watch?v=${videoId}`;

return [{
  json: {
    is_youtube: true,
    video_id: videoId,
    video_url: videoUrl,
    discord_message: messageContent,
    discord_shared_at: new Date().toISOString(),
    channel_id: message.channelId
  }
}];

const rawOutput = $input.first().json.stdout;

if (!rawOutput) {
  throw new Error('yt-dlp returned no output — video may be private, deleted, or geo-blocked');
}

// Decode Unicode escapes from JSON string values
function decodeUnicode(str) {
  try { return JSON.parse('"' + str + '"'); } catch (e) { return str; }
}

// Extract fields using regex since description may break JSON
const getId = rawOutput.match(/"id":"([^"]+)"/);
const getTitle = rawOutput.match(/"title":"([^"]+)"/);
const getChannel = rawOutput.match(/"channel":"([^"]+)"/);
const getDate = rawOutput.match(/"upload_date":"([^"]+)"/);
const getDuration = rawOutput.match(/"duration":(\d+)/);
const getViews = rawOutput.match(/"view_count":(\d+)/);

if (!getId) throw new Error('MISSING: video id not found');
if (!getTitle) throw new Error('MISSING: title not found');
if (!getChannel) throw new Error('MISSING: channel not found');
if (!getDate) throw new Error('MISSING: upload_date not found');
if (!getDuration) throw new Error('MISSING: duration not found');
if (!getViews) throw new Error('MISSING: view_count not found');

// Extract description: match up to the next known key
const descMatch = rawOutput.match(/"description":"([\s\S]*?)","view_count"/);
const description = descMatch ? decodeUnicode(descMatch[1]) : '';

const prevData = $('Extract YouTube URL').first().json;

return [{
  json: {
    video_id: getId[1],
    title: decodeUnicode(getTitle[1]),
    channel: decodeUnicode(getChannel[1]),
    upload_date: getDate[1],
    duration: parseInt(getDuration[1]),
    view_count: parseInt(getViews[1]),
    description: description,
    thumbnail_url: `https://img.youtube.com/vi/${getId[1]}/maxresdefault.jpg`,
    video_url: prevData.video_url,
    discord_shared_at: prevData.discord_shared_at,
    channel_id: prevData.channel_id,
    video_id_for_subs: getId[1]
  }
}];

const input = $input.first().json;
const prevData = $('Parse Metadata').first().json;

// Check if Read Subtitle File failed (continueOnFail)
if (input.error || !input.stdout || input.stdout.trim().length === 0) {
  throw new Error('No subtitles available for video: ' + prevData.video_id);
}

const vttContent = input.stdout;
const lines = vttContent.split('\n');
const textLines = [];
let lastLine = "";

for (let line of lines) {
    let trimmed = line.trim();

    // Skip VTT metadata and timestamps
    if (!trimmed || 
        trimmed === 'WEBVTT' || 
        trimmed.startsWith('Kind:') || 
        trimmed.startsWith('Language:') || 
        /^(\d{2}:)?\d{2}:\d{2}\.\d{3}/.test(trimmed) || 
        trimmed.includes('-->')) {
        continue;
    }

    // Remove HTML-like tags (styling)
    const cleaned = trimmed.replace(/<[^>]+>/g, '').trim();

    // Prevent duplicate adjacent lines (common in VTT)
    if (cleaned && cleaned !== lastLine) {
        textLines.push(cleaned);
        lastLine = cleaned;
    }
}

const transcript = textLines.join(' ');

return [{
    json: {
        ...prevData,
        transcript: transcript
    }
}];

const currentData = $('Parse Transcript').first().json;
const geminiOutput = $input.first().json;

const summary = geminiOutput.content.parts[0].text;

if (!summary) {
  throw new Error('MISSING: Gemini returned no summary text');
}

return [{
  json: {
    video_id: currentData.video_id,
    title: currentData.title,
    channel: currentData.channel,
    upload_date: currentData.upload_date,
    duration: currentData.duration,
    view_count: currentData.view_count,
    description: currentData.description,
    transcript: currentData.transcript,
    ai_summary: summary,
    thumbnail_url: currentData.thumbnail_url,
    discord_shared_at: currentData.discord_shared_at,
    channel_id: currentData.channel_id
  }
}];

const data = $('Prepare Insert Data').first().json;

return [{
  json: {
    video_id: data.video_id,
    process_status: 'success',
    error_type: null,
    notes: null
  }
}];

const errorData = $input.first().json;
const errorMessage = errorData.execution?.error?.message || 'Unknown error';
const errorNode = errorData.execution?.error?.node?.name || 'Unknown node';

// Determine error_type based on failing node
let errorType = 'unknown';
if (errorNode.includes('yt-dlp') || errorNode === 'Parse Metadata') {
  errorType = 'yt_dlp_failed';
} else if (errorNode === 'Parse Transcript') {
  errorType = errorMessage.includes('No subtitles') ? 'no_subtitles' : 'transcript_error';
} else if (errorNode.includes('model') || errorNode.includes('Gemini')) {
  errorType = 'gemini_error';
} else if (errorNode.includes('Supabase') || errorNode.includes('Insert')) {
  errorType = 'supabase_error';
} else if (errorNode.includes('Prepare')) {
  errorType = 'gemini_error';
}

// Try to extract video_id from error message
const vidMatch = errorMessage.match(/(?:video:\s*|video_id:\s*|yt_)([a-zA-Z0-9_-]{11})/);
const videoId = vidMatch ? vidMatch[1] : 'unknown';

return [{
  json: {
    video_id: videoId,
    process_status: 'error',
    error_type: errorType,
    notes: `[${errorNode}] ${errorMessage}`
  }
}];

// Get the full summary and title from the previous node
const summary = $('Prepare Insert Data').first().json.ai_summary || "No summary available";
const data = $('Prepare Insert Data').first().json;
const discordLimit = 2000; // Discord max message length
const safeLimit = 1900; // Leave some buffer
const chunks = [];

// Create the header for the very first message
const header = `Video saved! **${data.title}** by **${data.channel}** | Duration: ${Math.floor(data.duration / 60)}m ${data.duration % 60}s | ${data.view_count} views ---\n\n`;

let remainingText = summary;

// Loop through the text and break it into chunks intelligently
while (remainingText.length > 0) {
    // For the first chunk, reduce max length by the header size
    const isFirstChunk = chunks.length === 0;
    const maxLength = isFirstChunk ? safeLimit - header.length : safeLimit;

    if (remainingText.length <= maxLength) {
        // If the remaining text fits, add it and break
        chunks.push({ json: { chunk: (isFirstChunk ? header : "") + remainingText } });
        break;
    }

    // Find the last space within the limit to avoid breaking a word
    let splitIndex = remainingText.lastIndexOf(" ", maxLength);

    // If no space is found, split strictly at maxLength (fallback for long words)
    if (splitIndex === -1) {
        splitIndex = maxLength;
    }

    let chunkText = remainingText.substring(0, splitIndex);

    // Prepend the header only to the first chunk
    if (isFirstChunk) {
        chunkText = header + chunkText;
    }

    chunks.push({ json: { chunk: chunkText } });

    // Update remaining text for the next iteration
    remainingText = remainingText.substring(splitIndex).trim();
}

return chunks;
